def aggregate_spending_by_category(transactions):
    category_totals = {}

    for transaction in transactions:
        category = transaction['category']
        amount = transaction['amount']

        if category in category_totals:
            category_totals[category] += amount
        else:
            category_totals[category] = amount

    return category_totals

tests:
def test_aggregate_empty_list():
    result = aggregate_spending_by_category([])
    assert result == {}

def test_aggregate_single_category():
    data = [
        {'category': 'Groceries', 'amount': 25.50},
        {'category': 'Groceries', 'amount': 12.25}
    ]
    result = aggregate_spending_by_category(data)
    assert result['Groceries'] == 37.75

def test_aggregate_multiple_categories():
    data = [
        {'category': 'Books', 'amount': 15},
        {'category': 'Food', 'amount': 8.50},
        {'category': 'Books', 'amount': 20},
        {'category': 'Food', 'amount': 12.50},
        {'category': 'Entertainment', 'amount': 40}
    ]
    result = aggregate_spending_by_category(data)

    assert result['Books'] == 35
    assert result['Food'] == 21.0
    assert result['Entertainment'] == 40
    assert len(result) == 3

def test_aggregate_no_duplicate_categories():
    data = [
        {'category': 'A', 'amount': 10},
        {'category': 'B', 'amount': 20},
        {'category': 'C', 'amount': 30}
    ]
    result = aggregate_spending_by_category(data)
    assert result == {'A': 10, 'B': 20, 'C': 30}

