def analyze_connectivity(n: int, connections: list[tuple[int, int]]) -> list[int]:
    class UnionFind:
        def __init__(self, size):
            self.parent = list(range(size))
            self.rank = [0] * size
            self.component_count = size

        def find(self, i):
            root = i
            while self.parent[root] != root:
                root = self.parent[root]
            curr = i
            while curr != root:
                nxt = self.parent[curr]
                self.parent[curr] = root
                curr = nxt
            return root

        def union(self, i, j):
            root_i = self.find(i)
            root_j = self.find(j)
            if root_i != root_j:
                if self.rank[root_i] < self.rank[root_j]:
                    self.parent[root_i] = root_j
                elif self.rank[root_i] > self.rank[root_j]:
                    self.parent[root_j] = root_i
                else:
                    self.parent[root_j] = root_i
                    self.rank[root_i] += 1
                self.component_count -= 1
                return True
            return False

    uf = UnionFind(n)
    results = []
    for u, v in connections:
        uf.union(u, v)
        results.append(uf.component_count)
    return results

def organize_shopping_list(shopping_data):
    organized = {}
    for item, category in shopping_data:
        if category not in organized:
            organized[category] = []
        organized[category].append(item)
    return organized

