        self.max_size = max_size
        self.window = deque()
        self.max_deque = deque()  # Stores values in decreasing order

    def add_point(self, value: int):
        # 1. Update max_deque to maintain monotonic decreasing order
        while self.max_deque and self.max_deque[-1] < value:
            self.max_deque.pop()
        self.max_deque.append(value)

