from typing import Any, Callable, List, Optional


class Snapshot:
    """Manages the global snapshot scope and dependency tracking."""
    _instance: Optional['Snapshot'] = None

    def __init__(self):
        self.active_states: List['MutableState'] = []
        self.tracking_state: Optional['DerivedState'] = None
        self.is_tracking = False

    @classmethod
    def get_instance(cls) -> 'Snapshot':
        if cls._instance is None:
            cls._instance = cls()
        return cls._instance

    def start_tracking(self, derived: 'DerivedState') -> None:
        self.tracking_state = derived
        self.is_tracking = True

    def stop_tracking(self) -> None:
        self.tracking_state = None
        self.is_tracking = False


class MutableState:
    """Represents a reactive state holder."""
    def __init__(self, value: Any):
        self._value = value
        self._listeners: List[Callable] = []
        # Register with the current snapshot
        Snapshot.get_instance().active_states.append(self)

    @property
    def value(self) -> Any:
        snapshot = Snapshot.get_instance()
        if snapshot.is_tracking:
            # If we are inside a derived state calculation, record the dependency
            if snapshot.tracking_state not in snapshot.tracking_state.dependencies:
                snapshot.tracking_state.dependencies.append(self)
                self.observe(snapshot.tracking_state.invalidate)
        return self._value

    @value.setter
    def value(self, new_value: Any) -> None:
        if self._value != new_value:
            self._value = new_value
            for listener in self._listeners:
                listener()

    def observe(self, listener: Callable) -> None:
        self._listeners.append(listener)


class DerivedState:
    """Represents a derived value that updates based on dependencies."""
    def __init__(self, calculation: Callable):
        self._calculation = calculation
        self._value: Any = None
        self.dependencies: List[MutableState] = []
        self._recalculate()

    def _recalculate(self) -> None:
        snapshot = Snapshot.get_instance()
        snapshot.start_tracking(self)
        try:
            self._value = self._calculation()
        finally:
            snapshot.stop_tracking()

    @property
    def value(self) -> Any:
        if self._value is None:
            self._recalculate()
        return self._value

    def invalidate(self) -> None:
        # Triggered by dependency change
        self._recalculate()


def mutableStateOf(initial_value: Any) -> MutableState:
    """Factory function to create a MutableState."""
    return MutableState(initial_value)


def derivedStateOf(calculation: Callable) -> DerivedState:
    """Factory function to create a DerivedState."""
    return DerivedState(calculation)

