def parse_byte_range(total_size: int, range_header: str | None) -> dict:
    if not range_header or not isinstance(range_header, str):
        return {'valid': False, 'start': None, 'end': None, 'content_length': None, 'error': 'Missing or invalid Range header'}

    range_header = range_header.strip()
    if not range_header.lower().startswith('bytes='):
        return {'valid': False, 'start': None, 'end': None, 'content_length': None, 'error': 'Unsupported range unit'}

    range_spec = range_header[len('bytes='):].strip()
    if not range_spec:
        return {'valid': False, 'start': None, 'end': None, 'content_length': None, 'error': 'Empty range specification'}

    parts = range_spec.split('-')
    if len(parts) != 2:
        return {'valid': False, 'start': None, 'end': None, 'content_length': None, 'error': 'Invalid range format'}

    start_str, end_str = parts[0].strip(), parts[1].strip()

    if start_str == '':
        # Suffix range: -500
        if not end_str.isdigit() or int(end_str) <= 0:
            return {'valid': False, 'start': None, 'end': None, 'content_length': None, 'error': 'Invalid suffix length'}
        suffix_len = int(end_str)
        if suffix_len > total_size:
            suffix_len = total_size
        start = total_size - suffix_len
        end = total_size - 1
    elif end_str == '':
        # Open-ended range: 500-
        if not start_str.isdigit():
            return {'valid': False, 'start': None, 'end': None, 'content_length': None, 'error': 'Invalid start position'}
        start = int(start_str)
        end = total_size - 1
    else:
        # Closed range: 0-499
        if not start_str.isdigit() or not end_str.isdigit():
            return {'valid': False, 'start': None, 'end': None, 'content_length': None, 'error': 'Invalid range format'}
        start, end = int(start_str), int(end_str)

    if start < 0 or start >= total_size:
        return {'valid': False, 'start': None, 'end': None, 'content_length': None, 'error': 'Invalid range'}
    if end < start:
        return {'valid': False, 'start': None, 'end': None, 'content_length': None, 'error': 'Invalid range format'}

    # Clamp end if it exceeds total_size
    if end >= total_size:
        end = total_size - 1

    content_length = end - start + 1
    return {
        'valid': True,
        'start': start,
        'end': end,
        'content_length': content_length,
        'error': None
    }

import re

def evaluate_rest_preconditions(method: str, request_headers: dict, resource_etag: str) -> int | None:
    method_upper = method.upper()

    # Helper to parse the opaque tag from a raw ETag string
    def parse_opaque_tag(raw_tag: str) -> str:
        s = raw_tag.strip()
        is_weak = s.startswith('W/')
        if is_weak:
            s = s[2:].strip()
        if s.startswith('"') and s.endswith('"'):
            s = s[1:-1]
        # Unescape common escapes
        s = s.replace('\\"', '"').replace('\\\\', '\\')
        return s

    # Helper to parse the header value respecting quoted strings
    def parse_etag_list(header_value: str) -> list:
        tags = []
        if not header_value or not header_value.strip():
            return tags
        i = 0
        n = len(header_value)
        while i < n:
            # Skip whitespace
            while i < n and header_value[i] in ' \t':
                i += 1
            if i >= n:
                break

            # Check wildcard
            if header_value[i] == '*':
                tags.append({'value': None, 'is_wildcard': True})
                i += 1
                continue

            # Check for W/ prefix
            is_weak = False
            if header_value[i:i+2] == 'W/':
                is_weak = True
                i += 2
                while i < n and header_value[i] in ' \t':
                    i += 1

            # Expect opening quote
            if i < n and header_value[i] == '"':
                start = i
                i += 1
                while i < n:
                    if header_value[i] == '\\':
                        i += 2  # Skip escaped character
                        continue
                    if header_value[i] == '"':
                        break
                    i += 1
                if i < n:
                    i += 1  # Skip closing quote

                raw_opaque = header_value[start+1:i-1]
                # Unescape content
                opaque = raw_opaque.replace('\\"', '"').replace('\\\\', '\\')
                tags.append({'value': opaque, 'is_wildcard': False, 'is_weak': is_weak})
            else:
                # Malformed or unexpected format; skip
                break
        return tags

    # 1. Evaluate If-Match (Strong Comparison)
    if_m = request_headers.get('If-Match')
    if if_m is not None:
        tags = parse_etag_list(if_m)
        if not tags:
            # Empty header behaves like no match for If-Match
            if method_upper in ('PUT', 'PATCH', 'DELETE'):
                return 412

        has_wildcard = any(t['is_wildcard'] for t in tags)
        if has_wildcard:
            # If-Match: * matches only if resource does not exist
            if resource_etag is not None:
                return 412
        else:
            # Strong comparison: match opaque tags
            if resource_etag is None:
                return 412
            res_opaque = parse_opaque_tag(resource_etag)
            matched = False
            for t in tags:
                if t['value'] == res_opaque:
                    matched = True
                    break
            if not matched:
                return 412

    # 2. Evaluate If-None-Match (Weak Comparison, GET/HEAD only)
    if_nm = request_headers.get('If-None-Match')
    if if_nm is not None:
        if method_upper not in ('GET', 'HEAD'):
            # Ignore If-None-Match for other methods per requirements
            pass
        else:
            tags = parse_etag_list(if_nm)
            if not tags:
                # Empty header behaves like no match
                return None

            has_wildcard = any(t['is_wildcard'] for t in tags)
            if has_wildcard:
                # Wildcard matches any current representation
                # If resource doesn't exist, there is no current representation.
                # However, RFC says If-None-Match applies to existing resources.
                # If resource is missing, typically 404. But for this function,
                # we assume resource_etag is provided. If None, no match.
                if resource_etag is not None:
                    return 304
            else:
                # Weak comparison: opaque tags match regardless of W/
                if resource_etag is None:
                    return None
                res_opaque = parse_opaque_tag(resource_etag)
                for t in tags:
                    if t['value'] == res_opaque:
                        return 304

    return None

