import io

class LineBufferedWriter:
    def __init__(self, stream):
        self.stream = stream
        self.buffer = b''
        self.total_written = 0
        self.lines_written = 0

    def write_line(self, data: bytes) -> int:
        if not isinstance(data, bytes):
            raise TypeError("Data must be bytes")

        self.buffer += data

        if data.endswith(b'\n'):
            return self._flush_buffer()

        return len(data)

    def _flush_buffer(self):
        if not self.buffer:
            return 0

        written = self.stream.write(self.buffer)
        if written < len(self.buffer):
            raise IOError("Partial write occurred")

        self.total_written += len(self.buffer)
        self.lines_written += 1
        self.buffer = b''
        return written

    def flush(self):
        return self._flush_buffer()

    def close(self):
        self.flush()
        if hasattr(self.stream, 'close'):
            self.stream.close()

    @property
    def stats(self):
        return {'bytes': self.total_written, 'lines': self.lines_written}
