import re

def parse_config(text: str) -> dict:
    """
    Parses a configuration string with format: key=val, key="val", etc.
    Supports escape sequences in quoted values: \\, \" , \n, \t.
    """
    fields = {}
    i = 0
    length = len(text)

    # Regex for key: alphanumeric/underscore, allowing optional whitespace before equals
    key_regex = re.compile(r'([a-zA-Z_][a-zA-Z0-9_]*)\s*=')

    while i < length:
        # Skip leading whitespace before a key
        while i < length and text[i] in ' \t\r\n':
            i += 1

        if i >= length:
            break

        match = key_regex.match(text, i)
        if not match:
            # If we can't match a key, stop parsing (handles trailing commas/spaces)
            break

        key = match.group(1)
        i = match.end()

        # Skip whitespace after the key/equals
        while i < length and text[i] in ' \t\r\n':
            i += 1

        # Parse Value
        if i < length and text[i] == '"':
            # Quoted value
            i += 1  # Skip opening quote
            value_chars = []
            while i < length:
                if text[i] == '\\' and i + 1 < length:
                    next_char = text[i+1]
                    if next_char == '"':
                        value_chars.append('"')
                        i += 2
                    elif next_char == '\\':
                        value_chars.append('\\')
                        i += 2
                    elif next_char == 'n':
                        value_chars.append('\n')
                        i += 2
                    elif next_char == 't':
                        value_chars.append('\t')
                        i += 2
                    else:
                        # Unknown escape: preserve backslash and char
                        value_chars.append('\\')
                        value_chars.append(next_char)
                        i += 2
                elif text[i] == '"':
                    # Closing quote
                    i += 1  # Skip closing quote
                    break
                else:
                    value_chars.append(text[i])
                    i += 1
            fields[key] = ''.join(value_chars)
        else:
            # Unquoted value
            end = text.find(',', i)
            if end == -1:
                end = length
            # Strip whitespace for unquoted values
            fields[key] = text[i:end].strip()
            if end < length:
                i = end + 1  # Move past comma
            else:
                i = length

    return fields

