import os
import re
from enum import Enum, auto
from typing import Any, Dict, List, Optional


class TokenType(Enum):
    KEY = auto()
    EQUALS = auto()
    LBRACE = auto()
    RBRACE = auto()
    LBRACKET = auto()
    RBRACKET = auto()
    COMMA = auto()
    STRING = auto()
    NUMBER = auto()
    EOL = auto()
    EOF = auto()


class Token:
    def __init__(self, token_type: TokenType, value: Any):
        self.type = token_type
        self.value = value


class ConfigLexer:
    def __init__(self, text: str):
        self.text = text.replace('\r\n', '\n')
        self.pos = 0
        self.length = len(self.text)

    def next_token(self) -> Token:
        while self.pos < self.length:
            char = self.text[self.pos]

            if char.isspace():
                self.pos += 1
                continue

            if char == '#':
                while self.pos < self.length and self.text[self.pos] != '\n':
                    self.pos += 1
                continue

            if char == '=':
                self.pos += 1
                return Token(TokenType.EQUALS, '=')

            if char == '{':
                self.pos += 1
                return Token(TokenType.LBRACE, '{')

            if char == '}':
                self.pos += 1
                return Token(TokenType.RBRACE, '}')

            if char == '[':
                self.pos += 1
                return Token(TokenType.LBRACKET, '[')

            if char == ']':
                self.pos += 1
                return Token(TokenType.RBRACKET, ']')

            if char == ',':
                self.pos += 1
                return Token(TokenType.COMMA, ',')

            if char == '\n':
                self.pos += 1
                return Token(TokenType.EOL, '\n')

            if char == '\\':
                self.pos += 1
                if self.pos < self.length:
                    escaped = self.text[self.pos]
                    self.pos += 1
                    return Token(TokenType.STRING, f'\\{escaped}')
                return Token(TokenType.STRING, '\\')

            if char == '"':
                self.pos += 1
                val = []
                while self.pos < self.length:
                    c = self.text[self.pos]
                    if c == '"':
                        self.pos += 1
                        return Token(TokenType.STRING, ''.join(val))
                    if c == '\\':
                        self.pos += 1
                        if self.pos < self.length:
                            val.append(self.text[self.pos])
                            self.pos += 1
                        else:
                            raise ValueError("Unexpected end of string escape sequence")
                    else:
                        val.append(c)
                raise ValueError("Unterminated string literal")

            if char.isdigit() or (char == '-' and self.pos + 1 < self.length and self.text[self.pos + 1].isdigit()):
                num_str = []
                start = self.pos
                if char == '-':
                    num_str.append(char)
                    self.pos += 1
                while self.pos < self.length and (self.text[self.pos].isdigit() or self.text[self.pos] == '.'):
                    num_str.append(self.text[self.pos])
                    self.pos += 1
                s = ''.join(num_str)
                if '.' in s:
                    return Token(TokenType.NUMBER, float(s))
                return Token(TokenType.NUMBER, int(s))

            # Identifier / Key
            ident = []
            while self.pos < self.length and (self.text[self.pos].isalnum() or self.text[self.pos] in '_-'):
                ident.append(self.text[self.pos])
                self.pos += 1
            if ident:
                return Token(TokenType.KEY, ''.join(ident))

        return Token(TokenType.EOF, None)


class ConfigParser:
    def __init__(self, lexer: ConfigLexer):
        self.lexer = lexer
        self.current_token = self.lexer.next_token()

    def parse(self) -> Dict[str, Any]:
        result = self.parse_block_or_value()
        if self.current_token.type != TokenType.EOF:
            raise ValueError(f"Unexpected token {self.current_token.type} at position {self.lexer.pos}")
        if not isinstance(result, dict):
            raise ValueError("Configuration root must be a block")
        return result

    def parse_block_or_value(self) -> Any:
        token = self.current_token

        if token.type == TokenType.KEY:
            return self.parse_key_value_pair()
        elif token.type == TokenType.LBRACE:
            return self.parse_block()
        elif token.type == TokenType.LBRACKET:
            return self.parse_list()
        elif token.type == TokenType.STRING:
            return self.resolve_variables(token.value)
        elif token.type == TokenType.NUMBER:
            return token.value
        else:
            raise ValueError(f"Unexpected token {token.type} while expecting value")

    def parse_key_value_pair(self) -> Dict[str, Any]:
        key_token = self.current_token
        self.advance()
        if self.current_token.type != TokenType.EQUALS:
            raise ValueError(f"Expected '=' after key '{key_token.value}', got {self.current_token.type}")
        self.advance()
        value = self.parse_block_or_value()
        return {key_token.value: value}

    def parse_block(self) -> Dict[str, Any]:
        self.advance()  # consume {
        result = {}
        while self.current_token.type not in (TokenType.RBRACE, TokenType.EOF):
            if self.current_token.type == TokenType.KEY:
                entry = self.parse_key_value_pair()
                result.update(entry)
            else:
                raise ValueError(f"Expected key inside block, got {self.current_token.type}")
            if self.current_token.type == TokenType.EOL:
                self.advance()

        if self.current_token.type != TokenType.RBRACE:
            raise ValueError("Unterminated block")
        self.advance()  # consume }
        return result

    def parse_list(self) -> List[Any]:
        self.advance()  # consume [
        result = []
        while self.current_token.type not in (TokenType.RBRACKET, TokenType.EOF):
            value = self.parse_block_or_value()
            result.append(value)
            if self.current_token.type == TokenType.COMMA:
                self.advance()
            elif self.current_token.type != TokenType.RBRACKET and self.current_token.type != TokenType.EOL:
                raise ValueError(f"Expected ',' or ']' in list, got {self.current_token.type}")
            if self.current_token.type == TokenType.EOL:
                self.advance()

        if self.current_token.type != TokenType.RBRACKET:
            raise ValueError("Unterminated list")
        self.advance()  # consume ]
        return result

    def resolve_variables(self, text: str) -> Any:
        pattern = r'\{\{(\w+)\}\}'
        def replacer(match):
            var_name = match.group(1)
            val = os.environ.get(var_name)
            if val is not None:
                # Attempt type coercion similar to original logic
                try:
                    return int(val)
                except ValueError:
                    try:
                        return float(val)
                    except ValueError:
                        return val
            return match.group(0)

        resolved = re.sub(pattern, replacer, text)

        # Final coercion pass for the whole string if it looks like a number
        stripped = resolved.strip()
        if stripped.startswith('"') and stripped.endswith('"'):
            return stripped
        try:
            return int(stripped)
        except ValueError:
            try:
                return float(stripped)
            except ValueError:
                return stripped

    def advance(self):
        self.current_token = self.lexer.next_token()


def parse_config(text: str) -> Dict[str, Any]:
    lexer = ConfigLexer(text)
    parser = ConfigParser(lexer)
    return parser.parse()

