            val = ''
            if rest and rest[0] in ('"', "'"):
                quote_char = rest[0]
                val_chars = []
                i = 1
                while i < len(rest):
                    ch = rest[i]
                    if ch == '\\':
                        i += 1
                        if i < len(rest):
                            val_chars.append(rest[i])
                    elif ch == quote_char:
                        break
                    else:
                        val_chars.append(ch)
                    i += 1
                val = ''.join(val_chars)
            else:
                comment_idx = -1
                for idx, ch in enumerate(rest):
                    if ch == '#':
                        comment_idx = idx
                        break
                if comment_idx != -1:
                    val = rest[:comment_idx].rstrip()
                else:
                    val = rest.rstrip()

        if current_section:
            result[current_section][key] = val
        else:
            result[key] = val
    return result

