def test_simple_cycle():
    graph = {'A': ['B'], 'B': ['C'], 'C': ['A']}
    result = detect_deadlock_cycle(graph)
    assert result is not None
    assert set(result) == {'A', 'B', 'C'}
    # Cycle should be contiguous in the returned list
    assert result[-1] == 'C'
    # Check that C connects back to A (start of cycle relative to detection)
    # Since the cycle can start at any node depending on traversal, 
    # we verify the cyclic structure.
    assert graph[result[-1]][0] == result[0] or result[0] in graph[result[-1]]

def test_disconnected_acyclic_graph_false_positive_trap():
    # This is the specific case that triggers the bug.
