    # With the fix, 'path' is cleared after Component 1, so D sees A as visited but not in stack.
    graph = {
        'A': ['B'],
        'B': [],
        'C': ['D'],
        'D': ['A']
    }
    result = detect_deadlock_cycle(graph)
