def schema_aware_ingest(db_path, table_name, records, type_map=None):
    if type_map is None:
        type_map = {}

    if not records:
        return {"loaded": 0, "skipped": 0, "added_columns": [], "errors": []}

    conn = sqlite3.connect(db_path)
    cursor = conn.cursor()

    # Check if table exists
    cursor.execute(
        "SELECT name FROM sqlite_master WHERE type='table' AND name=?", 
        (table_name,)
    )
    table_exists = cursor.fetchone() is not None

    current_columns = set()
    if table_exists:
        cursor.execute(f"PRAGMA table_info('{table_name}')")
        current_columns = {col[1] for col in cursor.fetchall()}

    # Determine all columns needed
    all_keys = set()
    for r in records:
        all_keys.update(r.keys())

    # Determine columns to add and their types
    missing_columns = all_keys - current_columns
    added_columns = []
    column_types = {}

    for col in missing_columns:
        if col in type_map:
            column_types[col] = type_map[col]
        else:
