from typing import Any, Dict, Type, List

class DataError(Exception):
    def __init__(self, message: str, code: str = None):
        super().__init__(message)
        self.code = code

class SchemaMismatchError(DataError):
    def __init__(self, field: str, expected_type: Type, actual_value: Any):
        self.field = field
        self.expected_type = expected_type
        self.actual_type = type(actual_value)
        msg = f"Field '{field}': expected {expected_type.__name__}, got {self.actual_type.__name__}"
        super().__init__(msg, code="SCHEMA_MISMATCH")

class ConstraintViolationError(DataError):
    def __init__(self, field: str, constraint: str, value: Any):
        self.field = field
        self.constraint = constraint
        self.value = value
        msg = f"Field '{field}': constraint '{constraint}' violated by value {value}"
        super().__init__(msg, code="CONSTRAINT_VIOLATION")

class ValidationErrorCollection(DataError):
    def __init__(self, errors: List[DataError]):
        self.errors = errors
        msg = f"Validation failed with {len(errors)} errors"
        super().__init__(msg, code="VALIDATION_COLLECTION")

class DataProcessor:
    def __init__(self, schema: Dict[str, Type], strict: bool = True):
        self.schema = schema
        self.strict = strict

    def process(self, data: Dict[str, Any]) -> Dict[str, Any]:
        if not isinstance(data, dict):
            raise TypeError("Input must be a dictionary")

        errors = []
        result = data.copy()

        for field, expected_type in self.schema.items():
            if field not in result:
                errors.append(SchemaMismatchError(field, expected_type, None))
                continue

            if not isinstance(result[field], expected_type):
                errors.append(SchemaMismatchError(field, expected_type, result[field]))
                continue

            if expected_type == int and result[field] < 0:
                errors.append(ConstraintViolationError(field, "non_negative", result[field]))

        if errors:
            if self.strict:
                raise errors[0]
            else:
                raise ValidationErrorCollection(errors)

        return result
