    pass

class RetryableService:
    def __init__(self, name="service"):
        self.name = name
        self._error_log = []
        self._active = False

    @contextmanager
    def run_transaction(self):
        self._active = True
        try:
            yield self
        except Exception as e:
            self._error_log.append({
                "type": type(e).__name__,
                "message": str(e),
                "status": "failed"
            })
            raise
        finally:
            self._active = False

    def execute(self, operation, max_retries=3, backoff_factor=2.0):
        last_exc = None
        for attempt in range(max_retries):
            try:
                return operation()
            except TransientError as e:
                last_exc = e
                e.context["retry_attempt"] = attempt + 1
                self._error_log.append({"type": "TransientError", "status": "retried"})
                if attempt < max_retries - 1:
                    delay = backoff_factor ** attempt
                    time.sleep(delay)
            except TimeoutError:
                raise PermanentError("Operation timed out", code="TIMEOUT", context={"last_attempt": attempt})
            except PermanentError:
                raise
            except ValidationError:
                raise
            except Exception as e:
                raise PermanentError(f"Unexpected error: {str(e)}", code="UNKNOWN", context={"original_type": type(e).__name__})
        if last_exc is not None:
            last_exc.context["last_exception_message"] = last_exc.args[0]
        raise last_exc

    def get_summary(self):
        retried = sum(1 for e in self._error_log if e.get("status") == "retried")
        failed = sum(1 for e in self._error_log if e.get("status") == "failed")
        by_type = {}
        for e in self._error_log:
            t = e.get("type", "Unknown")
            by_type[t] = by_type.get(t, 0) + 1
        return {"total_errors": len(self._error_log), "retried": retried, "failed": failed, "by_type": by_type}
