def calculate_average_ages(file_path):
    import csv
    from collections import defaultdict

    def read_csv(file_path):
        try:
            with open(file_path, 'r') as file:
                return list(csv.reader(file))
        except FileNotFoundError:
            print(f'Error: The file {file_path} was not found.')
            return None
        except Exception as e:
            print(f'An error occurred while reading the file: {e}')
            return None

    def aggregate_ages(data):
        country_age_sum = defaultdict(int)
        country_age_count = defaultdict(int)

        for row in data[1:]:  # Skip header
            name, country, age = row
            age = int(age)
            country_age_sum[country] += age
            country_age_count[country] += 1

        return country_age_sum, country_age_count

    data = read_csv(file_path)
    if data is None:
        return {}

    country_age_sum, country_age_count = aggregate_ages(data)
    average_ages = {country: country_age_sum[country] / country_age_count[country] for country in country_age_sum}
    return average_ages

