def shortest_path(grid):
    if not grid or not grid[0]:
        return -1

    rows, cols = len(grid), len(grid[0])
    if grid[0][0] == 1 or grid[rows - 1][cols - 1] == 1:
        return -1

    queue = [(0, 0, 0)]
    visited = set((0, 0))

    while queue:
        current_x, current_y, distance = queue.pop(0)

        if current_x == rows - 1 and current_y == cols - 1:
            return distance

        for neighbor_x, neighbor_y in [(current_x + 1, current_y), (current_x - 1, current_y),
                                     (current_x, current_y + 1), (current_x, current_y - 1)]:
            if (0 <= neighbor_x < rows and 0 <= neighbor_y < cols and
                    grid[neighbor_x][neighbor_y] == 0 and
                    (neighbor_x, neighbor_y) not in visited):
                visited.add((neighbor_x, neighbor_y))
                queue.append((neighbor_x, neighbor_y, distance + 1))

    return -1

