import sqlite3
from contextlib import contextmanager

def create_connection(db_path):
    conn = sqlite3.connect(db_path)
    return conn

def initialize_db(conn):
    cursor = conn.cursor()
    cursor.execute('CREATE TABLE IF NOT EXISTS books (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    title TEXT NOT NULL,
                    author TEXT NOT NULL,
                    genre TEXT NOT NULL,
                    isbn TEXT NOT NULL UNIQUE
                 )')
    conn.commit()

@contextmanager
def get_cursor(conn):
    try:
        yield conn.cursor()
    except Exception as e:
        print(f'Database error: {e}')
        conn.rollback()
    finally:
        conn.close()

def add_book(conn, title, author, genre, isbn):
    with get_cursor(conn) as cursor:
        cursor.execute('INSERT INTO books (title, author, genre, isbn) VALUES (?, ?, ?, ?)', (title, author, genre, isbn))
        conn.commit()

def update_book(conn, book_id, title=None, author=None, genre=None, isbn=None):
    updates = []
    if title:
        updates.append((title, 'title'))
    if author:
        updates.append((author, 'author'))
    if genre:
        updates.append((genre, 'genre'))
    if isbn:
        updates.append((isbn, 'isbn'))
    with get_cursor(conn) as cursor:
        for value, column in updates:
            cursor.execute('UPDATE books SET ? = ? WHERE id = ?', (column, value, book_id))
        conn.commit()

def get_books_by_genre(conn, genre):
    with get_cursor(conn) as cursor:
        cursor.execute('SELECT * FROM books WHERE genre = ?', (genre,))
        return cursor.fetchall()

